const filePath = $input.first().json.result.file_path;
const token = 'TELEGRAM_BOT_TOKEN';
const url = `https://api.telegram.org/file/bot${token}/${filePath}`;
return [{ json: { downloadUrl: url } }];

const isVoice = $input.first().json.transcript !== undefined;
const msg = $('Valid Message?').first().json.body.message;
const text = $input.first().json.transcript || msg.text || msg.caption || '';
const chatId = msg.chat.id;
const photos = msg.photo;
const photoFileId = photos && photos.length > 0 ? photos[photos.length - 2 < 0 ? 0 : photos.length - 2].file_id : null;
return [{ json: { text, chatId: String(chatId), isVoice, photoFileId } }];

const CLAUDE_KEY = 'sk-ant-api03-REDACTED';
const WORKSPACE_WEBHOOK = 'https://n8n.gen-plasma.com/webhook/workspace-action';
const BOT_TOKEN = 'TELEGRAM_BOT_TOKEN';

const system = $('Get Context').item.json.context;
const rawHistory = $('Get History').item.json.history;
const history = Array.isArray(rawHistory) ? rawHistory : (Array.isArray(rawHistory && rawHistory.history) ? rawHistory.history : []);
const userText = $('Prepare Message').item.json.text;
const chatId = $('Prepare Message').item.json.chatId;
const isVoice = $('Prepare Message').item.json.isVoice;
const photoFileId = $('Prepare Message').item.json.photoFileId;

const tools = [{
  name: 'google_workspace',
  description: 'Perform Google Workspace actions: check/create/update/delete calendar events, read/send Gmail, list Drive files, manage Tasks. Use this when the user wants to interact with their calendar, email, or Drive.',
  input_schema: {
    type: 'object',
    properties: {
      tool: {
        type: 'string',
        description: 'The MCP tool name to call',
        enum: [
          'list_calendars','get_events','manage_event','query_freebusy',
          'search_gmail_messages','get_gmail_message_content','send_gmail_message','draft_gmail_message',
          'list_drive_items','search_drive_files','get_drive_file_content',
          'list_task_lists','list_tasks','manage_task',
          'search_docs','get_doc_as_markdown'
        ]
      },
      params: {
        type: 'object',
        description: 'Tool params. manage_event needs: action (create|update|delete), start_time and end_time as ISO 8601 strings e.g. 2026-04-04T10:00:00+01:00. calendar_id defaults to primary.',
        additionalProperties: true
      }
    },
    required: ['tool']
  }
}];

// Build user content — text only, or text + image
let userContent;
if (photoFileId) {
  try {
    // Get file path from Telegram (embed params in URL, no qs object)
    const fileInfoResp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.telegram.org/bot${BOT_TOKEN}/getFile?file_id=${encodeURIComponent(photoFileId)}`,
      json: true
    });
    const filePath = fileInfoResp.result && fileInfoResp.result.file_path;
    if (filePath) {
      const imageUrl = `https://api.telegram.org/file/bot${BOT_TOKEN}/${filePath}`;
      // Download image as binary and convert to base64
      const imgResp = await this.helpers.httpRequest({
        method: 'GET',
        url: imageUrl,
        returnFullResponse: true,
        encoding: 'arraybuffer'
      });
      const body = imgResp.body;
      const base64 = Buffer.isBuffer(body)
        ? body.toString('base64')
        : Buffer.from(body).toString('base64');
      const ext = filePath.split('.').pop().toLowerCase();
      const mimeType = ext === 'png' ? 'image/png' : ext === 'webp' ? 'image/webp' : 'image/jpeg';
      userContent = [
        { type: 'image', source: { type: 'base64', media_type: mimeType, data: base64 } },
        { type: 'text', text: userText || 'What do you see in this image?' }
      ];
    } else {
      userContent = userText || '(sent an image — could not download it)';
    }
  } catch(imgErr) {
    userContent = userText || '(sent an image — could not process it)';
  }
} else {
  userContent = userText || '...';
}

const messages = [...history, { role: 'user', content: userContent }];

const callClaude = async (msgs) => {
  try {
    return await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': CLAUDE_KEY,
        'anthropic-version': '2023-06-01'
      },
      body: {
        model: 'claude-sonnet-4-6',
        max_tokens: 1024,
        system: system || '',
        tools,
        messages: msgs
      },
      json: true
    });
  } catch(e) {
    const detail = (e.response && (e.response.data || e.response.body))
      ? JSON.stringify(e.response.data || e.response.body).slice(0, 300)
      : e.message;
    throw new Error('Claude API: ' + detail);
  }
};

let data = await callClaude(messages);

if (data.stop_reason === 'tool_use') {
  const toolBlock = data.content.find(b => b.type === 'tool_use');
  const wsData = await this.helpers.httpRequest({
    method: 'POST',
    url: WORKSPACE_WEBHOOK,
    body: { tool: toolBlock.input.tool, params: toolBlock.input.params || {} },
    json: true
  });

  messages.push({ role: 'assistant', content: data.content });
  messages.push({
    role: 'user',
    content: [{ type: 'tool_result', tool_use_id: toolBlock.id, content: wsData.content || JSON.stringify(wsData) }]
  });

  data = await callClaude(messages);
}

const text = (data.content || []).find(b => b.type === 'text')?.text || 'Sorry, something went wrong.';
return [{ json: { text, chatId, isVoice } }];

